const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const express = require('express');
const projectsService = require('./service');
const sendError = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Name is required');
  }
  try {
    const __existingProject = await projectsService.getProjectByName(name);
  if (__existingProject) return sendError(res, 409, 'PROJECT_DUPLICATE', 'Project already exists');
  const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    if (!project) return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    return res.json({ project });
  } catch (_error) {
    return sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});


module.exports = router;

const express = require('express');
const tasksService = require('./service');
const sendError = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    let tasks = await tasksService.getAllTasks(req.params.projectId);
    if (status === 'todo' || status === 'done') {
      tasks = tasks.filter(task => task.status === 'done');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.post('/', async (req, res) => {
  const { description } = req.body;
  if (!description) {
    return sendError(res, 400, 'INVALID_INPUT', 'Description is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, description);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!status || ![ 'todo', 'done' ].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid status');
  }
  try {
    const task = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let tasksStore = [];

const getAllTasks = async (projectId) => {
  return tasksStore.filter(task => task.projectId === projectId);
};

const createTask = async (projectId, description) => {
  const taskId = randomUUID();
  const task = { id: taskId, projectId, description, status: 'todo' };
  tasksStore.push(task);
  return task;
};

const updateTaskStatus = async (projectId, taskId, status) => {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId && task.projectId === projectId);
  if (taskIndex === -1) {
    return null;
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
};

module.exports = { getAllTasks, createTask, updateTaskStatus };

const express = require('express');
const membersService = require('./service');
const sendError = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'User ID and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    if (!member) return sendError(res, 409, 'MEMBER_DUPLICATE', 'Member already exists');
  res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let membersStore = [];

const addMember = async (projectId, userId, role) => {
  const memberId = randomUUID();
  const member = { id: memberId, projectId, userId, role };
  membersStore.push(member);
  return member;
};

module.exports = { addMember };

const express = require('express');
const commentsService = require('./service');
const sendError = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_INPUT', 'Message is required');
  }
  try {
    const comment = await commentsService.createComment(req.params.taskId, message);
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let commentsStore = [];

const createComment = async (taskId, message) => {
  const commentId = randomUUID();
  const comment = { id: commentId, taskId, message };
  commentsStore.push(comment);
  return comment;
};

module.exports = { createComment };

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };
